const body = $json.body || $json;
for (const k of ['provider','input','requestedBy','reason']) if (!body[k]) throw new Error(`${k} required`);
return [{ json: {
  correlationId: `inv-void-${Date.now()}-${Math.floor(Math.random()*1e6)}`,
  requestedAt: new Date().toISOString(),
  provider: body.provider,
  requestedBy: body.requestedBy,
  reason: body.reason,
  input: body.input
}}];

