// After Slack sendAndWait, $json carries the approval outcome.
// Officially exposed: $json.data.approved (boolean).
// Some n8n minor versions also surface $json.approved at top level.
const state = $node['Stamp correlation'].json;
const approved = (typeof $json.data?.approved === 'boolean') ? $json.data.approved
  : (typeof $json.approved === 'boolean') ? $json.approved
  : false;
// approver identity comes from Slack-verified user (n8n attaches when OAuth cred is used)
const approver = $json.data?.user?.username || $json.data?.user?.id || $json.user?.username || 'slack-unknown';
return [{ json: {
  ...state,
  decision: approved ? 'approve' : 'reject',
  approved,
  approver,
  decidedAt: new Date().toISOString()
}}];

const state = $node['Rehydrate after Wait'].json;
const statusCode = Number($json.statusCode ?? 0);
const ok = statusCode >= 200 && statusCode < 300;
return [{ json: { ...state, statusCode, ok, response: $json.body ?? $json } }];
